import * as ort from 'onnxruntime-web'
import localforage from 'localforage'

const MODEL_URL =
  'https://huggingface.co/smartyfh/big_lama/resolve/main/big_lama.onnx'
const MODEL_CACHE_KEY = 'lama_onnx_model'
const MAX_SIZE = 512

type ModelState = 'idle' | 'loading' | 'loaded' | 'error'
type ProgressCallback = (progress: number) => void

let modelState: ModelState = 'idle'
let modelSession: ort.InferenceSession | null = null
let progressCallback: ProgressCallback | null = null

// Configure ONNX Runtime for browser
ort.env.wasm.numThreads = navigator.hardwareConcurrency
  ? Math.min(navigator.hardwareConcurrency, 4)
  : 2

/**
 * Load image from File and return ImageData
 */
function loadImageFromFile(file: File): Promise<HTMLImageElement> {
  return new Promise((resolve, reject) => {
    const img = new Image()
    img.onload = () => resolve(img)
    img.onerror = reject
    const url = URL.createObjectURL(file)
    img.src = url
  })
}

/**
 * Load image from base64 data URL and return ImageData
 */
function loadImageFromDataURL(dataURL: string): Promise<HTMLImageElement> {
  return new Promise((resolve, reject) => {
    const img = new Image()
    img.onload = () => resolve(img)
    img.onerror = reject
    img.src = dataURL
  })
}

/**
 * Get ImageData from an image element using an offscreen canvas
 */
function getImageData(img: HTMLImageElement): ImageData {
  const canvas = document.createElement('canvas')
  canvas.width = img.naturalWidth
  canvas.height = img.naturalHeight
  const ctx = canvas.getContext('2d') as CanvasRenderingContext2D
  ctx.drawImage(img, 0, 0)
  return ctx.getImageData(0, 0, canvas.width, canvas.height)
}

/**
 * Calculate resize dimensions keeping aspect ratio, max side = maxSize
 */
function getResizeDimensions(
  width: number,
  height: number,
  maxSize: number
): { width: number; height: number } {
  if (width <= maxSize && height <= maxSize) {
    return { width, height }
  }
  const ratio = Math.min(maxSize / width, maxSize / height)
  return {
    width: Math.round(width * ratio),
    height: Math.round(height * ratio),
  }
}

/**
 * Resize ImageData to target dimensions
 */
function resizeImageData(
  imageData: ImageData,
  targetWidth: number,
  targetHeight: number
): ImageData {
  const canvas = document.createElement('canvas')
  canvas.width = targetWidth
  canvas.height = targetHeight
  const ctx = canvas.getContext('2d') as CanvasRenderingContext2D

  // Create a temp canvas to put the source image data
  const srcCanvas = document.createElement('canvas')
  srcCanvas.width = imageData.width
  srcCanvas.height = imageData.height
  const srcCtx = srcCanvas.getContext('2d') as CanvasRenderingContext2D
  srcCtx.putImageData(imageData, 0, 0)

  ctx.drawImage(srcCanvas, 0, 0, targetWidth, targetHeight)
  return ctx.getImageData(0, 0, targetWidth, targetHeight)
}

/**
 * Preprocess image and mask into tensors for LaMa model
 */
function preprocess(
  imageData: ImageData,
  maskData: ImageData
): {
  imageTensor: ort.Tensor
  maskTensor: ort.Tensor
  height: number
  width: number
} {
  const { width, height } = imageData

  // Resize to model input size
  const dims = getResizeDimensions(width, height, MAX_SIZE)
  const resizedImage = resizeImageData(imageData, dims.width, dims.height)
  const resizedMask = resizeImageData(maskData, dims.width, dims.height)

  const h = dims.height
  const w = dims.width
  const totalPixels = h * w

  // Image tensor: [1, 3, H, W], RGB, float32, normalized to [0, 1]
  const imageBuffer = new Float32Array(1 * 3 * h * w)
  const imgPixels = resizedImage.data

  for (let i = 0; i < totalPixels; i += 1) {
    // RGBA -> RGB, normalize
    imageBuffer[i] = imgPixels[i * 4] / 255.0 // R
    imageBuffer[totalPixels + i] = imgPixels[i * 4 + 1] / 255.0 // G
    imageBuffer[2 * totalPixels + i] = imgPixels[i * 4 + 2] / 255.0 // B
  }

  // Mask tensor: [1, 1, H, W], float32, binary (0 or 1)
  const maskBuffer = new Float32Array(1 * 1 * h * w)
  const maskPixels = resizedMask.data

  for (let i = 0; i < totalPixels; i += 1) {
    // Use the red channel of the mask (white = area to inpaint)
    maskBuffer[i] = maskPixels[i * 4] > 127 ? 1.0 : 0.0
  }

  const imageTensor = new ort.Tensor('float32', imageBuffer, [1, 3, h, w])
  const maskTensor = new ort.Tensor('float32', maskBuffer, [1, 1, h, w])

  return { imageTensor, maskTensor, height: h, width: w }
}

/**
 * Postprocess output tensor to data URL
 */
function postprocess(
  outputTensor: ort.Tensor,
  height: number,
  width: number
): string {
  const outputData = outputTensor.data as Float32Array
  // Output shape: [1, H, W, 3] in HWC format
  const totalPixels = height * width

  const canvas = document.createElement('canvas')
  canvas.width = width
  canvas.height = height
  const ctx = canvas.getContext('2d') as CanvasRenderingContext2D
  const imageData = ctx.createImageData(width, height)

  for (let i = 0; i < totalPixels; i += 1) {
    // HWC format: output is [1, H, W, 3]
    // Index in flat array: i = h * W + w
    // R channel at offset 0
    // G channel at offset totalPixels
    // B channel at offset 2 * totalPixels
    imageData.data[i * 4] = Math.min(
      255,
      Math.max(0, Math.round(outputData[i] * 255))
    ) // R
    imageData.data[i * 4 + 1] = Math.min(
      255,
      Math.max(0, Math.round(outputData[totalPixels + i] * 255))
    ) // G
    imageData.data[i * 4 + 2] = Math.min(
      255,
      Math.max(0, Math.round(outputData[2 * totalPixels + i] * 255))
    ) // B
    imageData.data[i * 4 + 3] = 255 // A
  }

  ctx.putImageData(imageData, 0, 0)
  return canvas.toDataURL('image/png')
}

/**
 * Load or retrieve cached model
 */
async function loadModel(): Promise<ort.InferenceSession> {
  if (modelSession) {
    return modelSession
  }

  modelState = 'loading'

  try {
    // Try to load from IndexedDB cache first
    const cachedModel = await localforage.getItem<ArrayBuffer>(MODEL_CACHE_KEY)
    if (cachedModel) {
      modelSession = await ort.InferenceSession.create(cachedModel)
      modelState = 'loaded'
      return modelSession
    }

    // Download model with progress tracking
    const response = await fetch(MODEL_URL)
    if (!response.ok) {
      throw new Error(`Failed to download model: ${response.statusText}`)
    }

    const contentLength = response.headers.get('content-length')
    const total = contentLength ? parseInt(contentLength, 10) : 0
    let loaded = 0

    const reader = response.body?.getReader()
    if (!reader) {
      throw new Error('Failed to get response reader')
    }

    const chunks: Uint8Array[] = []
    // eslint-disable-next-line no-constant-condition
    while (true) {
      const { done, value } = await reader.read() // eslint-disable-line no-await-in-loop
      if (done) break
      if (value) {
        chunks.push(value)
        loaded += value.length
        if (total > 0 && progressCallback) {
          progressCallback(Math.round((loaded / total) * 100))
        }
      }
    }

    // Combine chunks into single ArrayBuffer
    const modelBuffer = new Uint8Array(loaded)
    let offset = 0
    chunks.forEach(chunk => {
      modelBuffer.set(chunk, offset)
      offset += chunk.length
    })

    // Cache to IndexedDB
    await localforage.setItem(MODEL_CACHE_KEY, modelBuffer.buffer)

    // Create inference session
    modelSession = await ort.InferenceSession.create(modelBuffer.buffer)
    modelState = 'loaded'
    return modelSession
  } catch (error) {
    modelState = 'error'
    throw error
  }
}

/**
 * Get current model loading state
 */
export function getModelState(): ModelState {
  return modelState
}

/**
 * Register a callback for model loading progress (0-100)
 */
export function onModelProgress(callback: ProgressCallback): void {
  progressCallback = callback
}

/**
 * Main inpainting function using local ONNX LaMa model
 */
export default async function inpaint(
  imageFile: File,
  maskBase64: string,
  // eslint-disable-next-line @typescript-eslint/no-unused-vars
  _appCheckToken?: string
): Promise<string> {
  // Load model if not already loaded
  const session = await loadModel()

  // Load original image
  const image = await loadImageFromFile(imageFile)
  const imageData = getImageData(image)

  // Load mask from base64
  const mask = await loadImageFromDataURL(maskBase64)
  const maskImageData = getImageData(mask)

  // Preprocess: create tensors
  const { imageTensor, maskTensor, height, width } = preprocess(
    imageData,
    maskImageData
  )

  // Run inference
  const { inputNames } = session
  const feeds: Record<string, ort.Tensor> = {}

  // LaMa model expects 'image' and 'mask' inputs
  if (inputNames.includes('image')) {
    feeds.image = imageTensor
  } else {
    feeds[inputNames[0]] = imageTensor
  }

  if (inputNames.includes('mask')) {
    feeds.mask = maskTensor
  } else {
    feeds[inputNames[1]] = maskTensor
  }

  const results = await session.run(feeds)

  // Get output tensor
  const { outputNames } = session
  const outputTensor = results[outputNames[0]]

  if (!outputTensor) {
    throw new Error('No output tensor from model')
  }

  // Postprocess: convert to data URL
  return postprocess(outputTensor, height, width)
}
